def is_prime_filter(numbers):
    primes = []
    for num in numbers:
        if not isinstance(num, int):
            continue

        if num < 2:
            continue

        is_prime_flag = True
        for i in range(2, num):
            if num % i == 0:
                is_prime_flag = False
                break

        if is_prime_flag:
            primes.append(num)

    return primes
